import{_ as e,o as d,c as o,ag as r}from"./chunks/framework.OsDJF_Ea.js";const a="/docs/modules/step-sequencer.png",g=JSON.parse('{"title":"Step Sequencer","description":"","frontmatter":{},"headers":[],"relativePath":"modules/step-sequencer.md","filePath":"modules/step-sequencer.md"}'),s={name:"modules/step-sequencer.md"};function n(c,t,i,l,p,u){return d(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="step-sequencer" tabindex="-1">Step Sequencer <a class="header-anchor" href="#step-sequencer" aria-label="Permalink to &quot;Step Sequencer&quot;">​</a></h1><p><strong>Category:</strong> Control</p><p>8-part, 16-step trigger and velocity sequencer with built-in clock. Each part outputs a gate and a velocity signal per step. Steps cycle through off / low / med / high velocity on repeated press. Per-part loop start and end points enable polyrhythmic patterns. Runs standalone with internal BPM or syncs to an external clock. Click the module title to open the grid editor.</p><img src="'+a+'" alt="step-sequencer module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>clock</strong></td><td>External clock. Each pulse advances one step. Overrides the internal clock when connected.</td></tr><tr><td><strong>reset</strong></td><td>Resets all parts to step 0 on rising edge.</td></tr><tr><td><strong>start_stop</strong></td><td>Transport gate. 1 = run, 0 = stop.</td></tr><tr><td><strong>bpm</strong></td><td>BPM CV input. Overrides the internal <code>bpm</code> parameter when connected.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><p>Gate and velocity outputs are hidden by default and become visible as you connect them, or can be toggled with the <code>show_gate_outputs</code> / <code>show_velocity_outputs</code> parameters.</p><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>gate1</strong>..<strong>gate8</strong></td><td>Per-part gate outputs. High while a step is active. With <code>trigger_mode=true</code> they emit short trigger pulses; with <code>trigger_mode=false</code> they emit a sustained gate of length <code>gate_length</code> (fraction of step).</td></tr><tr><td><strong>vel1</strong>..<strong>vel8</strong></td><td>Per-part velocity outputs. 0 = off, 0.33 = low, 0.66 = med, 1.0 = high.</td></tr></tbody></table><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>bpm</code></td><td>120</td><td>Internal clock BPM (30-300).</td></tr><tr><td><code>use_self_clock</code></td><td>true</td><td>Use internal clock. Set false to require an external clock.</td></tr><tr><td><code>clock_div</code></td><td>4</td><td>Clock division. 1 = whole, 2 = half, 4 = quarter (16th steps).</td></tr><tr><td><code>bar_length</code></td><td>16</td><td>Steps per bar (16, 32 or 64).</td></tr><tr><td><code>step_resolution</code></td><td>16</td><td>Step subdivision. 16 = 16th notes, 32 = 32nd, 64 = 64th.</td></tr><tr><td><code>direction</code></td><td>forward</td><td>Playback direction. forward, backward, or ping-pong.</td></tr><tr><td><code>trigger_mode</code></td><td>true</td><td>True = short trigger pulse (good for drums and samples), false = sustained gate of <code>gate_length</code>.</td></tr><tr><td><code>gate_length</code></td><td>0.5</td><td>Gate length as a fraction of a step (only used when <code>trigger_mode=false</code>).</td></tr><tr><td><code>direction1</code>..<code>direction8</code></td><td>-1</td><td>Per-part direction override (-1 = use global).</td></tr><tr><td><code>resolution1</code>..<code>resolution8</code></td><td>-1</td><td>Per-part resolution override (-1 = use global).</td></tr><tr><td><code>trigger_mode1</code>..<code>trigger_mode8</code></td><td>-1</td><td>Per-part trigger/gate override (-1 = use global).</td></tr><tr><td><code>mute1</code>..<code>mute8</code></td><td>false</td><td>Per-part mute.</td></tr><tr><td><code>loop_start1</code>..<code>loop_start8</code></td><td>0</td><td>Per-part loop start step.</td></tr><tr><td><code>loop_end1</code>..<code>loop_end8</code></td><td>15</td><td>Per-part loop end step.</td></tr><tr><td><code>launch_quantize</code></td><td>1bar</td><td>Pattern switch quantize: beat, half, 1bar, 2bar.</td></tr><tr><td><code>active_pattern</code></td><td>0</td><td>Currently active pattern slot (0-7). Eight patterns can be stored per sequencer.</td></tr><tr><td><code>midi_out</code></td><td>false</td><td>Send USB MIDI note-on/off from gate outputs.</td></tr><tr><td><code>midi_note_base</code></td><td>36</td><td>Base MIDI note for part 1 (parts 1-8 map to base..base+7). 36 = GM kick.</td></tr><tr><td><code>midi_channel</code></td><td>9</td><td>MIDI channel (0-15). 9 = channel 10 (drums).</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Connect <code>gate1</code>..<code>gate8</code> to Drum Machine trigger inputs and <code>vel1</code>..<code>vel8</code> to its velocity inputs for a full drum sequencer. Use per-part loop start/end for polyrhythms -- e.g. part 1 looping 16 steps against part 2 looping 12 steps gives you a 4:3 polyrhythm. Double-tap a part button in the editor to set loop start/end. Save up to 8 patterns per sequencer and use <code>launch_quantize</code> to switch between them on bar boundaries. Enable <code>midi_out</code> to drive an external drum machine over USB MIDI.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',14)])])}const m=e(s,[["render",n]]);export{g as __pageData,m as default};
